import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X } from 'lucide-react';

const Header = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
  { name: 'Usługi', path: '#services' },
  { name: 'Proces', path: '#process' },
  { name: 'Blog', path: '#blog' },
  { name: 'Kontakt', path: '#contact' }];


  const handleScrollTo = (e, path) => {
    e.preventDefault();
    if (path.startsWith('#')) {
      const element = document.querySelector(path);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
        setIsMobileMenuOpen(false);
      }
    }
  };

  return (
    <header
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      isScrolled ? 'bg-black/80 backdrop-blur-md border-b border-white/10 py-4' : 'bg-transparent py-6'}`
      }>

      <div className="container mx-auto px-6 flex items-center justify-between">
        <Link to="/" className="text-2xl font-bold tracking-tighter text-white z-50">
          Visi<span className="text-[#00FFD1]">Logo</span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden md:flex items-center gap-8">
          {navLinks.map((link) =>
          <a
            key={link.name}
            href={link.path}
            onClick={(e) => handleScrollTo(e, link.path)}
            className="text-sm font-medium text-gray-300 hover:text-[#00FFD1] transition-colors uppercase tracking-widest">

              {link.name}
            </a>
          )}
          <a
            href="#contact"
            onClick={(e) => handleScrollTo(e, '#contact')}
            className="btn-primary text-xs uppercase tracking-widest px-6 py-3 h-auto">

            Darmowa Analiza
          </a>
        </nav>

        {/* Mobile Toggle */}
        <button
          className="md:hidden text-white z-50"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>

          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>

        {/* Mobile Menu */}
        <AnimatePresence>
          {isMobileMenuOpen &&
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="absolute top-0 left-0 w-full h-screen bg-black flex flex-col items-center justify-center gap-8 md:hidden">

              {navLinks.map((link) =>
            <a
              key={link.name}
              href={link.path}
              onClick={(e) => handleScrollTo(e, link.path)}
              className="text-2xl font-bold text-white hover:text-[#00FFD1]">

                  {link.name}
                </a>
            )}
            </motion.div>
          }
        </AnimatePresence>
      </div>
    </header>);

};

const Footer = () => {
  return (
    <footer className="bg-[#050505] border-t border-white/10 pt-20 pb-10">
      <div className="container mx-auto px-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-12 mb-16">
          <div className="col-span-1 md:col-span-2">
            <h2 className="text-3xl font-bold text-white mb-6">
              Visi<span className="text-[#00FFD1]">Logo</span>
            </h2>
            <p className="text-gray-400 max-w-md text-lg leading-relaxed">
              Tworzymy cyfrowe doświadczenia, które budują autorytet i sprzedają. 
              Minimalizm w formie, maksymalizm w wynikach.
            </p>
          </div>
          
          <div>
            <h4 className="text-white font-bold uppercase tracking-widest mb-6">Menu</h4>
            <ul className="space-y-4">
              <li><a href="#services" className="text-gray-400 hover:text-[#00FFD1] transition-colors">Usługi</a></li>
              <li><a href="#process" className="text-gray-400 hover:text-[#00FFD1] transition-colors">Proces</a></li>
              <li><a href="#blog" className="text-gray-400 hover:text-[#00FFD1] transition-colors">Blog</a></li>
              <li><a href="#contact" className="text-gray-400 hover:text-[#00FFD1] transition-colors">Kontakt</a></li>
            </ul>
          </div>
          
          <div>
            <h4 className="text-white font-bold uppercase tracking-widest mb-6">Kontakt</h4>
            <ul className="space-y-4">
              <li className="text-gray-400">reklamy@visilogo.info</li>
              <li className="text-gray-400">+48 536 837 946</li>
              <li className="text-gray-400">Kielce, Polska</li>
            </ul>
          </div>
        </div>
        
        <div className="border-t border-white/10 pt-8 flex flex-col md:flex-row justify-between items-center gap-4">
          <p className="text-gray-600 text-sm">
            © 2025 VisiLogo Agency. All rights reserved.
          </p>
          <div className="flex gap-6">
            <a href="#" className="text-gray-600 hover:text-white text-sm">Polityka Prywatności</a>
            <a href="#" className="text-gray-600 hover:text-white text-sm">Regulamin</a>
          </div>
        </div>
      </div>
    </footer>);

};

const Layout = ({ children }) => {
  return (
    <div className="min-h-screen bg-black text-white selection:bg-[#00FFD1] selection:text-black">
      <Header />
      <main>{children}</main>
      <Footer />
    </div>);

};

export default Layout;